import{_ as a}from"./Menu.bf643b41.js";import{u as o}from"./composables.a20be60a.js";import{r as e,a as n,e as c,b as p,f as s,o as u}from"./entry.b2c8d4ee.js";const l=""+new URL("p-ty-1.41b88692.png",import.meta.url).href,m=""+new URL("p-ty-2.e2a7fd5d.png",import.meta.url).href,d=""+new URL("p-ty-3.9025fa20.png",import.meta.url).href,h=""+new URL("p-ty-4.b5eb11a6.png",import.meta.url).href,v=""+new URL("p-ty-6.49ded97e.png",import.meta.url).href,g=""+new URL("p-ty-5.81a91c16.png",import.meta.url).href,f={class:"banniere"},_=s('<div class="margium-l marge-haute-l"><div class="espacium"><h1>Typographie</h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Projet libre </div><div class="colonne"><div class="projettitre">Ann\xE9es</div> Janvier 2020 \xE0 Novembre 2021 </div><div class="colonne"></div><div class="colonne"></div></div></div></div>',1),y=s('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p class="marge-basse-m">Attach\xE9 au design graphique, je me suis vite int\xE9ress\xE9 \xE0 la typographie. Elle permet de transmettre des \xE9motions et cr\xE9er des identit\xE9s remarquables, j&#39;ai souhait\xE9 apprendre \xE0 les concevoir pour dans un futur proche cr\xE9er une identit\xE9 visuelle compl\xE8te : du logo en passant par couleurs \xE0 la typographie.</p><h2>Chatertone</h2><img src="'+l+'" alt=""><p>Chatertone est la premi\xE8re police que j&#39;ai con\xE7ue, elle est exclusivement en majuscules ce qui permet d&#39;avoir beaucoup moins de glyphes \xE0 r\xE9aliser. Sur cette police, j&#39;ai fait beaucoup d&#39;erreurs typographiques, elle m&#39;a aussi pouss\xE9e \xE0 faire de nombreuses recherches. Elle m&#39;a aussi permis de s\xE9lectionner les logiciels et le processus que j&#39;allais utiliser pour concevoir les suivantes. J&#39;utilise le logiciel libre FontForge ainsi qu&#39;un logiciel classique de vectorisation comme Affinity designer pour dessiner chacun des glyphes qui seront assembl\xE9s apr\xE8s.</p><h2>\xC9trange</h2><img src="'+m+'" alt=""><p> Pour cette 2nde typographie, j&#39;ai souhait\xE9 r\xE9aliser une police fantaisiste qui soit un peu plus singuli\xE8re. J&#39;ai choisi le th\xE8me &quot;Dia de los Muertos&quot; qui est la f\xEAte des morts au Mexique pour cr\xE9er une typographie un peu \xE9trange, mais n\xE9anmoins festive, ce n&#39;est pas une typographie pour des affiches horreur ou de m\xE9tal, c&#39;est un peu plus enfantin, c&#39;est le sens que je voulais donner \xE0 cette typographie-l\xE0. Encore une fois, c&#39;est une typographie uniquement en capital. </p><h2>Cursivium</h2><img src="'+d+'" alt=""><p> Cette typographie cursive a \xE9t\xE9 l&#39;objet d&#39;un processus particulier, j&#39;ai scann\xE9 ma propre \xE9criture et nettoy\xE9 chacun des caract\xE8res pour dessiner cette police. C&#39;est la premi\xE8re police que je cr\xE9e avec des caract\xE8res en minuscules et majuscules. </p><h2>Vacances Romaines</h2><img src="'+h+'" alt=""><p> Le nom de la typographie provient du film Vacances Romaines avec Audrey Hepburn. J&#39;ai eu la volont\xE9 de cr\xE9er une police r\xE9tro et \xE0 la fois assez fine et romantique avec des accents tr\xE8s fins. C&#39;est une police cr\xE9\xE9e pour des titres et non un corps de texte. </p><h2>Cookies Sans</h2><img src="'+v+'" alt=""><p> Une police sans empattement, avec des formes tr\xE8s g\xE9om\xE9triques. Initialement pr\xE9vu pour r\xE9aliser des logotypes, sa graisse est volontairement plus \xE9lev\xE9e.</p><h2>Coeur S\xE9rif</h2><img src="'+g+'" alt=""><p> C\u0153ur S\xE9rif est une police fine avec empattement. Il est fortement recommand\xE9 de l&#39;utiliser sur des supports print avec une taille minimum de 48pt. </p></div></div></article>',1),R={__name:"typographie",setup(q){const t=e("Typographie - Lucas Lacroix"),i=e("");return o({title:t,meta:[{name:"description",content:i}]}),(b,j)=>{const r=a;return u(),n("div",null,[c("div",f,[p(r),_]),y])}}};export{R as default};
